+    #[test]
+    fn test_close_without_checkpoint_preserves_wal_recovery() {
+        let tmp = tempfile::tempdir().unwrap();
+        let db_path = tmp.path().join("skip-close-checkpoint.db");
+        let db_str = db_path.to_string_lossy().to_string();
+
+        let conn = Connection::open(&db_str).unwrap();
+        conn.execute("CREATE TABLE t (x INTEGER)").unwrap();
+        conn.execute("INSERT INTO t VALUES (41)").unwrap();
+
+        conn.close_without_checkpoint().unwrap();
+
+        let reopened = Connection::open(&db_str).unwrap();
+        let rows = reopened.query("SELECT x FROM t").unwrap();
+        assert_eq!(rows.len(), 1);
+        assert_eq!(rows[0].values()[0], SqliteValue::Integer(41));
+        reopened.close().unwrap();
+    }
